baseCreate.query:
mutation GiftCardLiveHybridOverlayBaseCreate(
  $first: GiftCardCreateInput!
  $second: GiftCardCreateInput!
  $third: GiftCardCreateInput!
  $fourth: GiftCardCreateInput!
) {
  first: giftCardCreate(input: $first) {
    giftCard { id lastCharacters enabled expiresOn initialValue { amount currencyCode } balance { amount currencyCode } }
    userErrors { field message }
  }
  second: giftCardCreate(input: $second) {
    giftCard { id lastCharacters enabled expiresOn initialValue { amount currencyCode } balance { amount currencyCode } }
    userErrors { field message }
  }
  third: giftCardCreate(input: $third) {
    giftCard { id lastCharacters enabled expiresOn initialValue { amount currencyCode } balance { amount currencyCode } }
    userErrors { field message }
  }
  fourth: giftCardCreate(input: $fourth) {
    giftCard { id lastCharacters enabled expiresOn initialValue { amount currencyCode } balance { amount currencyCode } }
    userErrors { field message }
  }
}

initialValueBase.query:
query GiftCardLiveHybridOverlayRead($query: String!, $sortKey: GiftCardSortKeys!) {
  forward: giftCards(first: 4, query: $query, sortKey: $sortKey) {
    nodes {
      id
      lastCharacters
      enabled
      expiresOn
      initialValue {
        amount
        currencyCode
      }
      balance {
        amount
        currencyCode
      }
    }
    edges {
      cursor
      node {
        id
        lastCharacters
        enabled
        expiresOn
        initialValue {
          amount
          currencyCode
        }
        balance {
          amount
          currencyCode
        }
      }
    }
    pageInfo {
      hasNextPage
      hasPreviousPage
      startCursor
      endCursor
    }
  }
  reverse: giftCards(first: 2, query: $query, sortKey: $sortKey, reverse: true) {
    nodes {
